  sap: { id: 'sap', title: 'SAP S/4HANA', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 0, position: { x: 120, y: 100 }, size: { width: 1280, height: 800 } },
  fsm: { id: 'fsm', title: 'IFS FSM', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 0, position: { x: 160, y: 140 }, size: { width: 1280, height: 800 } },
  mobile: { id: 'mobile', title: 'Technician Device', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 0, position: { x: 900, y: 80 }, size: { width: 400, height: 740 } },
  console: { id: 'console', title: 'AEDIL Console', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 0, position: { x: 100, y: 80 }, size: { width: 1280, height: 800 } },
  settings: { id: 'settings', title: 'System Settings', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 0, position: { x: 350, y: 200 }, size: { width: 900, height: 650 } },
  porta: { id: 'porta', title: 'AEDIL Porta', isOpen: false, isMinimized: false, isMaximized: false, zIndex: 100, position: { x: 300, y: 80 }, size: { width: 400, height: 740 } },
