const ContextualActions = () => {
   const { activeAppId, agent, selectedEmailId, sapForm, performAutoFill, performDispatch, switchToApp, emails, performScan, performDiagnosis, diagnosis, submitDiagnosisFeedback, viewTicketAnalysis, manualOverride } = useOS();
   const activeEmail = emails.find(e => e.id === selectedEmailId);
   const hasData = activeEmail?.data;

   if (activeAppId === 'outlook') {
      if (!hasData && activeEmail) {
         return <ActionButton onClick={performScan} label="Scan & Extract Entities" subLabel="AI Analysis" icon={Sparkles} color="indigo" />;
      }
      if (hasData) {
         return <ActionButton onClick={() => switchToApp('sap')} label="Open SAP S/4HANA" subLabel="Data Ready for Transfer" icon={LayoutGrid} color="blue" />;
      }
      return <div className="text-[11px] text-center text-slate-500 py-2 border border-dashed border-white/10 rounded-xl">Select an email to activate Neural Core</div>;
   }

   if (activeAppId === 'sap') {
      if (!sapForm.equipment && hasData) {
         return <ActionButton onClick={performAutoFill} label="Inject Data to Mask" subLabel="Auto-Fill Form" icon={Copy} color="amber" />;
      }
      if (sapForm.equipment && sapForm.isDirty) {
          if (!diagnosis) {
             return <ActionButton onClick={performDiagnosis} label="Run Diagnostics" subLabel="Multi-Agent Analysis" icon={Brain} color="purple" />;
          } else if (diagnosis.isComplete) {
             // Multi-button Action Cluster for Diagnosis Decision
             return (
               <div className="flex flex-col gap-2">
                  <ActionButton 
                     onClick={() => {
                        submitDiagnosisFeedback(diagnosis.ticketId, 'approved');
                        performDispatch();
                     }}
                     label="Approve & Dispatch" 
                     subLabel="Send to Technician" 
                     icon={Zap} 
                     color="emerald" 
                  />
                  <div className="flex gap-2">
                     <button 
                        onClick={() => viewTicketAnalysis(diagnosis.ticketId)}
                        className="flex-1 bg-[#1A1A20] hover:bg-[#202028] border border-white/10 text-white py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2 group"
                     >
                        <Search className="w-3.5 h-3.5 text-indigo-400 group-hover:text-indigo-300" /> Inspect
                     </button>
                     <button 
                        onClick={manualOverride}
                        className="flex-1 bg-[#1A1A20] hover:bg-red-500/10 border border-white/10 hover:border-red-500/30 text-slate-400 hover:text-red-400 py-3 rounded-2xl text-xs font-bold transition-all flex items-center justify-center gap-2"
                     >
                        <X className="w-3.5 h-3.5" /> Reject
                     </button>
                  </div>
               </div>
             );
          }
      }
   }

   if (activeAppId === 'fsm') {
      return <ActionButton onClick={() => switchToApp('mobile')} label="View Technician Device" subLabel="Live Mirror" icon={ArrowRight} color="zinc" />;
   }

   return null;
};

const ActionButton = ({ onClick, label, subLabel, icon: Icon, color }: any) => {
   const colors: any = {
      indigo: "bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/25",
      blue: "bg-blue-600 hover:bg-blue-500 shadow-blue-500/25",
      amber: "bg-amber-600 hover:bg-amber-500 shadow-amber-500/25",
      purple: "bg-purple-600 hover:bg-purple-500 shadow-purple-500/25",
      emerald: "bg-emerald-600 hover:bg-emerald-500 shadow-emerald-500/25",
      zinc: "bg-zinc-700 hover:bg-zinc-600 shadow-zinc-500/25"
   };

   return (
      <motion.button 
         whileHover={{ scale: 1.02 }}
         whileTap={{ scale: 0.98 }}
         onClick={onClick}
         className={`w-full py-3.5 px-5 rounded-2xl flex items-center gap-4 text-left shadow-lg transition-all group ${colors[color]}`}
