        case 'IoT': return 'bg-purple-900/20 text-purple-400 border-purple-500/20';
        case 'Manuals': return 'bg-slate-800 text-slate-400 border-slate-600/30';
        case 'History': return 'bg-rose-900/20 text-rose-400 border-rose-500/20';
        case 'Inventory': return 'bg-amber-900/20 text-amber-400 border-amber-500/20';
        default: return 'bg-white/5 text-slate-400 border-white/10';
    }
};

