import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useOS } from '../../store';
import { Zap, Check, AlertCircle, Loader2, LayoutGrid, Copy, ArrowRight, Sparkles, Brain, Box, Link as LinkIcon, Network, X, Search, Package } from 'lucide-react';
import { ReasoningStep, WindowState } from '../../types';

export const AedilOverlay: React.FC = () => {
  const { activeAppId, agent, windows, selectedEmailId, emails, sapForm, assignedTech } = useOS();
  const [expanded, setExpanded] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [agent.logs]);

  useEffect(() => {
     if (agent.status !== 'idle') setExpanded(true);
  }, [agent.status]);

  // --- CONTEXT AWARENESS ENGINE ---
  const hasExtractedData = emails.some(e => e.data);
  let isRelevant = false;
  let hintText = "AEDIL Active";
  let contextLabel = "System Idle";
  let accentColor = "from-indigo-500 via-purple-500 to-amber-500";
  let icon = Sparkles;

  if (agent.status !== 'idle') {
      isRelevant = true;
      hintText = agent.status === 'diagnosing' ? "Diagnosing Issue..." : "Processing...";
      contextLabel = "Neural Agent Working";
      accentColor = agent.status === 'diagnosing' ? "from-amber-500 to-orange-600" : "from-indigo-500 to-cyan-500";
      icon = Loader2;
  } else if (activeAppId === 'outlook') {
      contextLabel = "Connected to Outlook";
      icon = Network;
      isRelevant = true; // Always show in Outlook to show "Connectedness"
      const email = emails.find(e => e.id === selectedEmailId);
      if (email?.data) {
         hintText = "Entity Data Ready";
         accentColor = "from-emerald-500 to-teal-400";
         icon = Check;
      } else if (email) {
         hintText = "Analyze Content";
         accentColor = "from-blue-500 to-indigo-500";
         icon = Brain;
      } else {
         hintText = "Awaiting Selection";
         accentColor = "from-slate-500 to-slate-400";
      }
  } else if (activeAppId === 'sap') {
      contextLabel = "Connected to SAP S/4HANA";
      icon = LayoutGrid;
      isRelevant = true;
      if (hasExtractedData && !sapForm.equipment) {
          hintText = "Auto-Fill Available";
          accentColor = "from-amber-500 to-yellow-400";
          icon = Copy;
      } else if (sapForm.equipment && sapForm.isDirty) {
          hintText = "Diagnosis Ready";
          accentColor = "from-purple-600 to-pink-500";
          icon = Brain;
      } else {
          hintText = "Monitoring Fields";
          accentColor = "from-blue-600 to-blue-400";
      }
  } else if (activeAppId === 'fsm') {
      isRelevant = true;
      contextLabel = "Connected to IFS FSM";
      if (assignedTech) {
          hintText = "Sync to Mobile";
          accentColor = "from-zinc-600 to-zinc-400";
          icon = ArrowRight;
      } else {
          hintText = "Monitoring Schedule";
          accentColor = "from-purple-600 to-indigo-600";
      }
  }

  if (!activeAppId || !windows[activeAppId]) return null;
  const activeWindow = windows[activeAppId];

  // Prevent overlay from attaching to these specific apps
  if (activeAppId === 'console' || activeAppId === 'settings' || activeAppId === 'mobile' || activeAppId === 'porta') return null;

  // Show overlay even if window is minimized, but require active app context
  if (!activeWindow.isOpen) return null;

  // Always show if relevant or expanded
  if (!isRelevant && !expanded) return null;

  const isMaximized = activeWindow.isMaximized;

  // Calculate position using FIXED positioning logic
  // If maximized: Top Right of Viewport with padding
  // If windowed: Top Right of the Window Rect
  const winX = isMaximized ? 0 : (activeWindow.position?.x || 0);
  const winY = isMaximized ? 0 : (activeWindow.position?.y || 0); // Remove offset for fixed
  const winWidth = isMaximized ? window.innerWidth : (activeWindow.size?.width || 900);

  // Position relative to viewport (Fixed)
  const anchorX = winX + winWidth - (isMaximized ? 60 : 40); 
  const anchorY = winY + (isMaximized ? 60 : 40); // Push down a bit to clear traffic lights

  // Ultra-Smooth Transition Config
  const springConfig = { type: "spring", stiffness: 400, damping: 30, mass: 0.8 };

  return (
    <motion.div
       layout
       className="fixed z-[999999] pointer-events-auto flex flex-col items-end font-sans"
       initial={false}
       animate={{ 
          left: anchorX,
          top: anchorY,
       }}
       transition={springConfig}
       style={{ transform: 'translateX(-100%)' }} // Anchor right
    >
       <AnimatePresence mode="wait">
          {expanded ? (
             <ExpandedNeuralCore key="expanded" setExpanded={setExpanded} scrollRef={scrollRef} contextLabel={contextLabel} activeAppId={activeAppId} />
          ) : (
             <IdleNeuralPill key="collapsed" setExpanded={setExpanded} hintText={hintText} accentColor={accentColor} icon={icon} />
          )}
       </AnimatePresence>
    </motion.div>
  );
};

