import React, { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useOS } from '../../store';
import { Zap, Check, AlertCircle, Loader2, LayoutGrid, Copy, ArrowRight, Sparkles, Brain, Box, Link as LinkIcon, Network, X, Search, Package, Warehouse, Truck } from 'lucide-react';
import { WindowState } from '../../types';

export const AedilOverlay: React.FC = () => {
  const { activeAppId, agent, windows, selectedEmailId, emails, sapForm, assignedTech } = useOS();
  const [expanded, setExpanded] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logs
  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [agent.logs]);

  // Auto-expand on agent activity
  useEffect(() => {
     if (agent.status !== 'idle') setExpanded(true);
  }, [agent.status]);

  // --- CONTEXT AWARENESS ENGINE ---
  const hasExtractedData = emails.some(e => e.data);
  let isRelevant = false;
  let hintText = "AEDIL";
  let contextLabel = "System Idle";
  let accentColor = "from-indigo-500 via-purple-500 to-amber-500";
  let icon = Sparkles;

  if (agent.status !== 'idle') {
      isRelevant = true;
      hintText = agent.status === 'diagnosing' ? "Diagnosing..." : "Processing...";
      contextLabel = "Neural Agent Working";
      accentColor = agent.status === 'diagnosing' ? "from-amber-500 to-orange-600" : "from-indigo-500 to-cyan-500";
      icon = Loader2;
  } else if (activeAppId === 'outlook') {
      contextLabel = "Connected to Outlook";
      icon = Network;
      isRelevant = true; 
      const email = emails.find(e => e.id === selectedEmailId);
      if (email?.data) {
         hintText = "Data Ready";
         accentColor = "from-emerald-500 to-teal-400";
         icon = Check;
      } else if (email) {
         hintText = "Analyze";
         accentColor = "from-blue-500 to-indigo-500";
         icon = Brain;
      } else {
         hintText = "Waiting";
         accentColor = "from-slate-500 to-slate-400";
      }
  } else if (activeAppId === 'sap') {
      contextLabel = "Connected to SAP S/4HANA";
      icon = LayoutGrid;
      isRelevant = true;
      if (hasExtractedData && !sapForm.equipment) {
          hintText = "Auto-Fill";
          accentColor = "from-amber-500 to-yellow-400";
          icon = Copy;
      } else if (sapForm.equipment && sapForm.isDirty) {
          hintText = "Diagnosis";
          accentColor = "from-purple-600 to-pink-500";
          icon = Brain;
      } else {
          hintText = "Monitoring";
          accentColor = "from-blue-600 to-blue-400";
      }
  } else if (activeAppId === 'fsm') {
      isRelevant = true;
      contextLabel = "Connected to IFS FSM";
      if (assignedTech) {
          hintText = "Sync Mobile";
          accentColor = "from-zinc-600 to-zinc-400";
          icon = ArrowRight;
      } else {
          hintText = "Schedule";
          accentColor = "from-purple-600 to-indigo-600";
      }
  }

  // Window Tracking Logic
  if (!activeAppId || !windows[activeAppId]) return null;
  const activeWindow = windows[activeAppId];
  if (activeAppId === 'console' || activeAppId === 'settings' || activeAppId === 'mobile' || activeAppId === 'porta') return null;
  if (!activeWindow.isOpen) return null;
  if (!isRelevant && !expanded) return null;

  const isMaximized = activeWindow.isMaximized;

  // Calculate Anchor Position
  const winX = isMaximized ? 0 : (activeWindow.position?.x || 0);
  const winY = isMaximized ? 0 : (activeWindow.position?.y || 0);
  const winWidth = isMaximized ? window.innerWidth : (activeWindow.size?.width || 900);

  const anchorX = winX + winWidth - (isMaximized ? 60 : 40); 
  const anchorY = winY + (isMaximized ? 60 : 40); 

  // --- ANIMATION CONFIGURATION ---
  // Using a single layoutId container for morphing.
  // The 'spring' physics here are tuned for "Heavy Premium" feel (high stiffness, high damping).
  const transition = { 
      type: "spring", 
      stiffness: 320, 
      damping: 32, 
      mass: 1 
  };

  return (
    <motion.div
       className="fixed z-[999999] pointer-events-auto flex flex-col items-end font-sans"
       initial={false}
       animate={{ 
          left: anchorX,
          top: anchorY,
       }}
       // We use a separate transition for the position to make window following smoother/faster
       // than the expansion animation
       transition={{ type: "spring", stiffness: 400, damping: 28 }}
       style={{ transform: 'translateX(-100%)' }} 
    >
       {/* SINGLE MORPHING CONTAINER */}
       <motion.div
          layout
          onClick={() => !expanded && setExpanded(true)}
          className={`relative overflow-hidden bg-[#0A0A0A]/95 backdrop-blur-2xl border border-white/15 shadow-[0_20px_60px_-10px_rgba(0,0,0,0.8),0_0_0_1px_rgba(255,255,255,0.1)] ${expanded ? 'cursor-default' : 'cursor-pointer group'}`}
          initial={false}
          animate={{
             width: expanded ? 360 : 'auto', // Auto width for pill, fixed for card
             height: expanded ? 'auto' : 44,
             borderRadius: expanded ? 24 : 99,
          }}
          transition={transition}
          style={{ minWidth: expanded ? 360 : 44 }} // Prevent text wrap glitches
       >
          {/* BACKGROUND EFFECTS */}
          <motion.div 
             className={`absolute inset-0 bg-gradient-to-br ${accentColor} opacity-5 transition-opacity duration-500 pointer-events-none`} 
          />
          {expanded && (
             <motion.div 
                initial={{ opacity: 0 }} 
                animate={{ opacity: 1 }} 
                className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-indigo-500/20 via-purple-500/5 to-transparent pointer-events-none" 
             />
