const ConfigInput = ({ label, value, secure }: { label: string, value: string, secure?: boolean }) => (
    <div>
        <label className="text-[10px] font-bold text-slate-400 mb-1.5 block uppercase tracking-wide">{label}</label>
        <div className="relative">
            <input 
                type={secure ? "password" : "text"} 
                defaultValue={value} 
                className="w-full bg-black/30 border border-white/10 rounded-lg px-3 py-2.5 text-xs text-slate-200 font-mono focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/20 outline-none transition-all shadow-inner" 
            />
