    'AEDIL Porta': { icon: Mic, color: '#8B5CF6', category: 'Voice AI', description: 'Voice Intake Agent' },
    'IoT Alert': { icon: Radio, color: '#EF4444', category: 'Sensor', description: 'Azure IoT Hub / MQTT' },

