    'Dynamics 365': { icon: Server, color: '#002050', category: 'ERP', description: 'F&O / Business Central' },
    'Oracle': { icon: Database, color: '#C74634', category: 'DB', description: 'Oracle Fusion Cloud' },
    'ServiceMax': { icon: Settings, color: '#F96332', category: 'FSM', description: 'Asset 360' },
