const GlassNode = ({ node, selected, isTesting }: any) => {
    const providerConfig = PROVIDER_LIBRARY[node.provider] || DEFAULT_PROVIDER;
    const Icon = providerConfig.icon;
    const accentColor = providerConfig.color;

    return (
        <motion.div 
            layoutId={node.id} 
            initial={{ scale: 0, opacity: 0 }} 
            animate={{ scale: selected ? 1.05 : 1, opacity: 1 }} 
            exit={{ scale: 0, opacity: 0 }} 
            data-node-id={node.id} 
            className={`
                absolute w-[240px] h-[120px] rounded-2xl pointer-events-auto transition-all duration-200 group cursor-grab active:cursor-grabbing backdrop-blur-md overflow-hidden
                ${selected 
                    ? 'bg-[#1E1E2E]/95 ring-2 shadow-[0_0_50px_-10px_rgba(99,102,241,0.4)] z-20' 
                    : 'bg-[#0F1019]/80 border border-white/10 hover:border-white/30 shadow-xl z-10'
                }
            `} 
            style={{ 
                left: node.position.x, 
                top: node.position.y,
                borderColor: selected ? accentColor : 'rgba(255,255,255,0.1)'
            }}
        >
            {/* Top accent line */}
            <div className="absolute top-0 left-0 w-full h-1" style={{ backgroundColor: accentColor }}></div>

            {/* Content */}
            <div className="h-full p-4 flex flex-col relative z-10">
                <div className="flex items-start gap-3.5 mb-auto">
                    {/* Icon Box */}
                    <div 
                        className="w-10 h-10 rounded-xl flex items-center justify-center shadow-lg border border-white/5 shrink-0"
                        style={{ backgroundColor: `${accentColor}20` }} // 20% opacity
                    >
                        <Icon style={{ color: accentColor }} className="w-5 h-5" strokeWidth={2} />
                    </div>

                    {/* Titles */}
                    <div>
                        <div className="text-[13px] font-bold text-white leading-tight mb-0.5">{node.provider}</div>
                        <div className="text-[10px] text-slate-400 font-medium">{node.label}</div>
                    </div>
                </div>

                {/* Footer Metrics */}
                <div className="flex items-center justify-between mt-3 pt-3 border-t border-white/5">
                    <span 
                        className="text-[9px] font-bold px-2 py-0.5 rounded-md border border-white/5 uppercase tracking-wide"
                        style={{ color: accentColor, backgroundColor: `${accentColor}10` }}
