                        {providerConfig.category}
                    </span>
                    <div className="flex items-center gap-1.5 text-[9px] text-slate-500 font-mono">
                        {isTesting && <Loader2 className="w-3 h-3 animate-spin text-emerald-500" />}
                        <span>Ready</span>
                    </div>
                </div>
            </div>

            {/* Testing Ping Effect */}
            {isTesting && (
                <div className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-emerald-500 rounded-full border-2 border-[#0F1019] z-30 animate-ping" />
            )}

            {/* Connectors */}
            {node.type !== 'trigger' && <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-[#1E293B] border border-slate-600 shadow-sm group-hover:bg-white transition-colors" />}
            {node.type !== 'action' && <div className="absolute -right-1.5 top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-[#1E293B] border border-slate-600 shadow-sm group-hover:bg-white transition-colors" />}
        </motion.div>
    );
};

