      },

      assignedTech: null,
      dispatchStatus: 'idle',
      selectedSlot: null,

      diagnosis: null,
      inspectingTicketId: null,

      mobile: {
        isOpen: false,
        diagnosisStatus: 'pending',
        partsOrdered: false,
        chatHistory: [
          { id: 'msg1', sender: 'ai', text: 'Hi, I have analyzed the ticket. Waiting for dispatch details...', timestamp: Date.now() }
        ],
        debriefStatus: 'pending',
        feedback: null
      },

      porta: {
        messages: [
           { id: 'init', sender: 'ai', text: 'Hallo, hier ist Porta. Wie kann ich helfen?', timestamp: Date.now() }
        ],
        status: 'idle',
        transcript: ''
      },

      agent: {
        status: 'idle',
        activeTask: null,
        logs: [{ id: 'init', timestamp: Date.now(), type: 'info', message: 'AEDIL Neural Core initialized.' }]
      },

      workflowNodes: INITIAL_WORKFLOW_NODES,
      workflowEdges: INITIAL_WORKFLOW_EDGES,
      isGeneratingWorkflow: false,

      knowledgeNodes: INITIAL_KNOWLEDGE_NODES,
      knowledgeEdges: INITIAL_KNOWLEDGE_EDGES,
      learningEvents: [],
      cortexMessages: [
         { id: 'c1', sender: 'ai', text: 'Neural Cortex Online. I am ready to analyze system knowledge.', timestamp: Date.now() }
      ],
      isCortexThinking: false,

      setOpenAIApiKey: (key) => set({ openaiApiKey: key }),

      openApp: (id) => set((state) => {
        const maxZ = Math.max(0, ...(Object.values(state.windows) as WindowState[]).map(w => w.zIndex || 0));
        return {
          windows: {
            ...state.windows,
            [id]: { ...state.windows[id], isOpen: true, isMinimized: false, zIndex: maxZ + 1 }
          },
          activeAppId: id
        };
      }),

      closeApp: (id) => set((state) => ({
        windows: { ...state.windows, [id]: { ...state.windows[id], isOpen: false, isMaximized: false } },
        activeAppId: state.activeAppId === id ? null : state.activeAppId
      })),

      focusApp: (id) => set((state) => {
        const maxZ = Math.max(0, ...(Object.values(state.windows) as WindowState[]).map(w => w.zIndex || 0));
        if (state.windows[id].zIndex === maxZ) return {}; // Already on top
        return {
          windows: { ...state.windows, [id]: { ...state.windows[id], zIndex: maxZ + 1, isMinimized: false } },
          activeAppId: id
        };
      }),

      minimizeApp: (id) => set((state) => ({
        windows: { ...state.windows, [id]: { ...state.windows[id], isMinimized: true } },
        activeAppId: state.activeAppId === id ? null : state.activeAppId
      })),

      toggleMaximizeApp: (id) => set((state) => {
        const maxZ = Math.max(0, ...(Object.values(state.windows) as WindowState[]).map(w => w.zIndex || 0));
        const isMax = !state.windows[id].isMaximized;
        return {
          windows: { 
            ...state.windows, 
            [id]: { 
              ...state.windows[id], 
              isMaximized: isMax,
              isMinimized: false,
              zIndex: maxZ + 1
            } 
          },
          activeAppId: id
        };
      }),

      switchToApp: (id) => set((state) => {
        const currentApp = state.activeAppId;
        const maxZ = Math.max(0, ...(Object.values(state.windows) as WindowState[]).map(w => w.zIndex || 0));
        const newWindows = { ...state.windows };

        if (currentApp && currentApp !== id) {
          newWindows[currentApp] = { ...newWindows[currentApp], isMinimized: true };
        }
        newWindows[id] = { ...newWindows[id], isOpen: true, isMinimized: false, zIndex: maxZ + 1 };
        return { windows: newWindows, activeAppId: id };
      }),

      updateWindowPosition: (id, position) => set((state) => ({
        windows: { ...state.windows, [id]: { ...state.windows[id], position } }
      })),

      updateWindowSize: (id, size) => set((state) => ({
        windows: { ...state.windows, [id]: { ...state.windows[id], size } }
      })),

      selectEmail: (id) => set({ selectedEmailId: id }),
      updateEmailBody: (id, body) => set(state => ({ emails: state.emails.map(e => e.id === id ? { ...e, body } : e) })),
      updateSapField: (field, value) => set((state) => ({ sapForm: { ...state.sapForm, [field]: value, isDirty: true } })),
      assignTech: (techName) => set((state) => {
         const newTickets = [...state.tickets];
         if (newTickets.length > 0) {
             newTickets[0] = { 
                 ...newTickets[0], 
                 status: 'DISPATCHED',
                 assignedTech: techName 
             };
         }
         return { 
             assignedTech: techName,
             tickets: newTickets
         };
      }),
      toggleSmartLens: (isOpen) => set(state => ({ mobile: { ...state.mobile, isOpen } })),
      acceptDiagnosis: () => set(state => ({ mobile: { ...state.mobile, diagnosisStatus: 'accepted' } })),
      rejectDiagnosis: () => set(state => ({ mobile: { ...state.mobile, diagnosisStatus: 'rejected' } })),
      orderParts: () => set(state => ({ mobile: { ...state.mobile, partsOrdered: true } })),

      // --- AI LOGIC ---
      sendTechMessage: async (text) => {
        const { mobile, diagnosis } = get();
        const currentHistory = mobile.chatHistory;
        const newUserMsg = { id: Date.now().toString(), sender: 'tech', text, timestamp: Date.now() };

        set(state => ({
          mobile: { ...state.mobile, chatHistory: [...state.mobile.chatHistory, newUserMsg as any] }
        }));

        try {
            const apiKey = getApiKey();
            if (!apiKey) throw new Error("API Key Missing");

            const ai = new GoogleGenAI({ apiKey });
            const activeTicket = get().tickets[0] || MOCK_TICKETS[0];

            let context = `You are Curio, an expert industrial AI assistant. 
            Ticket Context: #${activeTicket.number}.
            Customer: ${activeTicket.customer.name}. 
            Equipment: ${activeTicket.equipment.model}.
            Error: ${activeTicket.error.code} - ${activeTicket.error.description}.`;

            if (diagnosis && diagnosis.isComplete) {
                context += `\nDiagnosis: Primary Fault: ${diagnosis.primaryFault.fault} (${diagnosis.primaryFault.confidence}%). Reasoning: ${diagnosis.primaryFault.reasoning}.`;
            } else {
                context += `\nDiagnosis: Pending.`;
            }

            const systemInstruction = `${context} Keep answers brief, professional, and technical. Do not markdown your response.`;

            const history = currentHistory.map(msg => ({
                role: msg.sender === 'tech' ? 'user' : 'model',
                parts: [{ text: msg.text }]
            }));

            const chat = ai.chats.create({ model: 'gemini-2.5-flash', config: { systemInstruction }, history });
            const result = await chat.sendMessage({ message: text });
            const responseText = result.text;

            const newAiMsg = { id: (Date.now()+1).toString(), sender: 'ai', text: responseText, timestamp: Date.now() };
            set(state => ({ mobile: { ...state.mobile, chatHistory: [...state.mobile.chatHistory, newAiMsg as any] } }));
        } catch (err) {
           console.error("AI Error", err);
           const errorMsg = { id: (Date.now()+1).toString(), sender: 'ai', text: "Connection interrupted. Using cached manual data.", timestamp: Date.now() };
           set(state => ({ mobile: { ...state.mobile, chatHistory: [...state.mobile.chatHistory, errorMsg as any] } }));
        }
      },

      setPortaStatus: (status) => set(state => ({ porta: { ...state.porta, status } })),
      addPortaMessage: (sender, text) => set(state => ({ porta: { ...state.porta, messages: [...state.porta.messages, { id: Date.now().toString(), sender, text, timestamp: Date.now() }] } })),

      processPortaInput: async (text) => {
          const { porta, addPortaMessage, setPortaStatus } = get();
          addPortaMessage('user', text);
          setPortaStatus('processing');

          try {
              const apiKey = getApiKey();
              if (!apiKey) throw new Error("API Key Missing");

              const ai = new GoogleGenAI({ apiKey });
              const systemInstruction = `You are AEDIL Porta, a voice intake agent.`;

              const history = porta.messages.map(msg => ({ role: msg.sender === 'user' ? 'user' : 'model', parts: [{ text: msg.text }] }));
              const chat = ai.chats.create({ model: 'gemini-2.5-flash', config: { systemInstruction }, history });
              const result = await chat.sendMessage({ message: text });

              addPortaMessage('ai', result.text);
              setPortaStatus('idle');
          } catch (err) {
              setPortaStatus('idle');
              addPortaMessage('ai', "Connection error.");
          }
      },

      finalizePortaSession: async (extractedFields?: any[]) => {
         const { addAgentLog, openApp, closeApp, selectEmail } = get();

         // Use functional update to avoid overwriting recent messages
         set(state => ({ porta: { ...state.porta, status: 'processing' } }));
         get().addPortaMessage('system', 'Generiere Ticket und Service-Bericht...');

         try {
            const apiKey = getApiKey();

            // Get full transcript with clear labeling
            const currentPorta = get().porta;
            let transcript = currentPorta.messages
                .filter(m => m.sender !== 'system')
                .map(m => `${m.sender === 'user' ? 'CUSTOMER' : 'AGENT'}: ${m.text}`)
                .join('\n');

            if (!transcript || transcript.length < 10) {
                transcript = "CUSTOMER: [No audible transcript recorded]";
            }

            // Basic extraction from UI as fallback/hint
            const uiData: any = {};
            extractedFields?.forEach(f => { uiData[f.id] = f.value; });

            let refinedData: any = { ...uiData };
            let emailBody = "";

            if (apiKey) {
                const ai = new GoogleGenAI({ apiKey });

                // Enhanced Prompt for High Quality Ticket (German)
                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash',
                    contents: `
                    Analyze this support call transcript (German/English mixed).
                    TRANSCRIPT:
                    ${transcript}

                    TASK 1: Extract structured data (JSON).
                    - customer: Company name. If not explicit, infer from context or use "Unknown".
                    - contact: Person name.
                    - equipment: Model/Serial. Look for alphanumeric codes like "EJC 220" or "516...".
                    - error: Error code (e.g. E0015). If none, use "General".
                    - priority: Assess urgency (1-Very High, 2-High, 3-Medium).
                    - desc: Short symptom description (max 10 words).

                    TASK 2: Write a professional Service Ticket Email Body in German.
                    - Include ALL relevant details from the conversation.
                    - Use professional formatting.

                    OUTPUT JSON FORMAT:
                    {
                      "customer": "...",
                      "contact": "...",
                      "equipment": "...",
                      "error": "...",
                      "priority": "...",
                      "desc": "...",
                      "emailSubject": "...",
                      "emailBody": "..."
                    }
                    `,
                    config: { responseMimeType: 'application/json' }
                });

                const text = response.text;
                // Parse JSON safely
                try {
                     const jsonBlock = text.match(/```json\n([\s\S]*?)\n```/)?.[1] || text.replace(/```json|```/g, '');
                     const llmData = JSON.parse(jsonBlock);
                     refinedData = { ...refinedData, ...llmData };
                     emailBody = llmData.emailBody;
                } catch(e) { console.warn("LLM Parse Error", e); }
            }

            // Fallback body with transcript if AI generation fails or produces empty body
            const fallbackBody = `Automatische Meldung (KI-Extraktion unvollständig).\n\nTRANSKRIPT:\n${transcript}\n\n---\nBitte manuell prüfen.`;

            // Defaults if LLM fails or info missing
            const data = {
                customer: refinedData.customer || "Unbekannter Kunde",
                contact: refinedData.contact || "Kein Kontakt",
                equipment: refinedData.equipment || "Gerät unbekannt",
                error: refinedData.error || "N/A",
                priority: refinedData.priority || "Medium",
                desc: refinedData.desc || "Störung gemeldet",
                emailSubject: refinedData.emailSubject || `Störungsmeldung: ${refinedData.customer || 'Unbekannt'}`,
                emailBody: emailBody && emailBody.length > 20 ? emailBody : fallbackBody
            };

            // Synthetic Address Generation
            const charCodeSum = (str: string) => str.split('').reduce((sum, char) => sum + char.charCodeAt(0), 0);
            const seed = charCodeSum(data.customer);
            const cities = ["Berlin", "Hamburg", "München", "Köln", "Frankfurt", "Stuttgart"];
            const city = cities[seed % cities.length];
            const generatedAddress = `${10000 + (seed % 80000)} ${city}, Industriestr. ${seed % 100}`;
            const generatedDebitorId = (50000000 + (seed % 999999)).toString();

            const newTicket: Ticket = { 
                ...MOCK_TICKETS[0], 
                id: `T-${Date.now()}`, 
                number: Math.floor(100000 + Math.random() * 900000).toString(), 
                customer: { 
                    name: data.customer, 
                    debitorId: generatedDebitorId,
                    contact: data.contact,
                    phone: "N/A",
                    email: "support@customer.com",
                    location: generatedAddress 
                }, 
                equipment: { ...MOCK_TICKETS[0].equipment, model: data.equipment }, 
                error: { code: data.error, description: data.desc, customerReport: data.emailBody }, // Use full body as report
                priority: data.priority,
                status: 'NEW',
                createdAt: new Date().toISOString()
            };

            const newEmail: Email = {
                id: `e-${Date.now()}`,
                sender: 'AEDIL Porta <intake@aedil.ai>',
                subject: data.emailSubject,
                time: 'Gerade eben',
                unread: true,
                body: data.emailBody,
                data: {
                    ticketId: newTicket.number,
                    customer: data.customer,
                    customerAddress: generatedAddress,
                    debitorId: generatedDebitorId,
                    equipment: data.equipment,
                    error: data.error,
                    priority: data.priority,
                    desc: data.desc
                }
            };

            // Update Store State
            set(state => ({
                tickets: [newTicket, ...state.tickets],
                emails: [newEmail, ...state.emails],
                sapForm: {
                    ...state.sapForm,
                    customerAddress: generatedAddress, 
                    soldToParty: generatedDebitorId,
                    customerName: data.customer,
                    equipment: data.equipment,
                    priority: data.priority,
                    shortText: data.desc,
                    errorDesc: data.emailBody,
                    isDirty: true
                },
                porta: { ...state.porta, status: 'completed' }
            }));

            addAgentLog('success', 'Ticket und E-Mail erfolgreich generiert.');

            // Workflow Transition and State Reset
            setTimeout(() => {
                closeApp('porta');
                openApp('outlook');
                selectEmail(newEmail.id);
                addAgentLog('info', 'Neues Ticket via Outlook empfangen.');

                // Reset Porta Session for a clean start next time
                set(state => ({
                    porta: {
                        messages: [{ id: Date.now().toString(), sender: 'ai', text: 'Hallo, hier ist Porta. Wie kann ich helfen?', timestamp: Date.now() }],
                        status: 'idle',
                        transcript: ''
                    }
                }));
            }, 1000);

         } catch (err) {
            console.error("Finalization failed", err);
            set(state => ({ porta: { ...state.porta, status: 'idle' } }));
            get().addPortaMessage('system', 'Fehler bei der Ticketgenerierung.');
            addAgentLog('error', 'Generierung fehlgeschlagen.');
         }
      },

      submitJobFeedback: (correct, voiceNote) => set(state => ({})),

      addAgentLog: (type, message) => set((state) => ({ agent: { ...state.agent, logs: [...state.agent.logs, { id: Math.random().toString(), timestamp: Date.now(), type, message }] } })),

      performScan: async () => {
          const { agent, selectedEmailId, emails, addAgentLog } = get();
          if (!selectedEmailId) return;
          set({ agent: { ...agent, status: 'reading' } });
          addAgentLog('thinking', 'Porta is scanning email content...');

          setTimeout(() => {
              const email = emails.find(e => e.id === selectedEmailId);
              if (email && email.data) {
                 set(state => ({
                     agent: { ...state.agent, status: 'idle' },
                     emails: state.emails.map(e => e.id === selectedEmailId ? { ...e, data: e.data } : e)
                 }));
                 addAgentLog('success', 'Entity extraction complete.');
              }
          }, 1500);
      },

      performAutoFill: () => {
          const { selectedEmailId, emails, addAgentLog, switchToApp } = get();
          const email = emails.find(e => e.id === selectedEmailId);
          if (!email || !email.data) return;

          addAgentLog('action', 'Injecting data into SAP S/4HANA...');
          setTimeout(() => {
              set(state => ({
                  sapForm: {
                      ...state.sapForm,
                      equipment: email.data!.equipment,
                      soldToParty: email.data!.debitorId,
                      customerAddress: email.data!.customerAddress || state.sapForm.customerAddress,
                      customerName: email.data!.customer, 
                      priority: email.data!.priority,
                      shortText: email.data!.error,
                      errorDesc: email.data!.desc,
                      isDirty: true
                  }
              }));
              switchToApp('sap');
              addAgentLog('success', 'SAP Form populated.');
          }, 1000);
      },

      performDispatch: () => {
          const { switchToApp, addAgentLog } = get();
          addAgentLog('action', 'Opening Scheduler for Dispatch Assignment...');
          set({ dispatchStatus: 'planning', selectedSlot: null });
          switchToApp('fsm');
      },

      selectDispatchSlot: (techId: string, techName: string, time: string) => {
          set({ 
              dispatchStatus: 'review', 
              selectedSlot: { techId, techName, time } 
          });
      },

      finalizeDispatch: () => {
          const { addAgentLog, selectedSlot } = get();
          if (!selectedSlot) return;

          set(state => {
              const newTickets = [...state.tickets];
              if (newTickets.length > 0) {
                  newTickets[0] = { ...newTickets[0], status: 'DISPATCHED', assignedTech: selectedSlot.techName };
              }
              return {
                  assignedTech: selectedSlot.techName,
                  tickets: newTickets,
                  dispatchStatus: 'confirmed',
                  diagnosis: null, // Clear diagnosis as we are moving to next phase
                  selectedSlot: null
              };
          });
          addAgentLog('success', `Job dispatched to ${selectedSlot.techName} at ${selectedSlot.time}.`);
      },

      performDiagnosis: async (ticketId) => {
          const { addAgentLog, tickets } = get();
          const targetTicketId = ticketId || tickets[0].id; 
          const ticket = tickets.find(t => t.id === targetTicketId || t.number === targetTicketId) || tickets[0];

          set({ agent: { status: 'diagnosing', activeTask: 'Initializing Curio...', logs: get().agent.logs } });
          addAgentLog('thinking', 'Curio is accessing real-time tools...');

          const diagnosisResult = await CurioService.generateRealDiagnosis(ticket.id, ticket);

          // GENERATE CONTEXT AWARE MOBILE CHAT MESSAGE
          const analysisMsg = {
             id: Date.now().toString(),
             sender: 'ai',
             text: `Hi ${get().assignedTech?.split(' ')[0] || 'Technician'}, I have analyzed the ticket for ${ticket.customer.name}. Based on ${ticket.error.code || 'the reported issue'} and the symptoms, I am ${diagnosisResult.primaryFault?.confidence || 85}% confident it is the ${diagnosisResult.primaryFault?.fault || 'suspected component'}.`,
             timestamp: Date.now()
          };

          set(state => {
              const newTickets = [...state.tickets];
              const ticketIndex = newTickets.findIndex(t => t.id === ticket.id);
              if (ticketIndex !== -1) {
                  newTickets[ticketIndex] = { ...newTickets[ticketIndex], status: 'DIAGNOSED' };
              }

              return { 
                  diagnosis: diagnosisResult as any,
                  agent: { ...state.agent, status: 'idle' },
                  tickets: newTickets,
                  mobile: {
                      ...state.mobile,
                      chatHistory: [analysisMsg as any] // Reset/Seed history with relevant data
                  }
              };
          });

          addAgentLog('success', `Diagnosis complete. ${diagnosisResult.primaryFault?.confidence}% Confidence.`);
      },

      viewTicketAnalysis: (ticketId) => {
          const { switchToApp } = get();
          switchToApp('console');
          set({ inspectingTicketId: ticketId });
      },

      closeTicketAnalysis: () => set({ inspectingTicketId: null }),

      submitDiagnosisFeedback: (ticketId, status, reason) => {
         const { diagnosis } = get();
         if (diagnosis) {
             set({ diagnosis: { ...diagnosis, feedback: { status, reason, timestamp: Date.now() } } });
         }
      },

      manualOverride: () => {
          const { diagnosis, addAgentLog } = get();
          if (diagnosis) {
              set({ 
                  diagnosis: { 
                      ...diagnosis, 
                      feedback: { status: 'rejected', reason: 'Manual Override by Operator', timestamp: Date.now() }
                  },
                  sapForm: { ...get().sapForm, isDirty: true }
              });
              addAgentLog('action', 'Manual Override activated. Diagnosis rejected.');
          }
      },

      simulateElevenLabsIntake: () => {
          // Placeholder for triggering simulation
      },

      generateWorkflow: async (prompt) => {
          set({ isGeneratingWorkflow: true });
          // Simulation of workflow generation
          setTimeout(() => {
              set({ isGeneratingWorkflow: false });
          }, 2000);
      },

      addWorkflowNode: (type, label, provider, parentId, position) => {
          const id = Math.random().toString();

          // Use provided position or auto-calculate based on parent
          let newPos = position || { x: 400, y: 300 };

          if (!position && parentId) {
              const parent = get().workflowNodes.find(n => n.id === parentId);
              if (parent) {
                  newPos = { x: parent.position.x + 350, y: parent.position.y };
              }
          } else if (!position) {
              // Add to end if not specified
              const lastNode = get().workflowNodes[get().workflowNodes.length - 1];
              if (lastNode) {
                  newPos = { x: lastNode.position.x + 350, y: lastNode.position.y };
              }
          }

          const newNode: WorkflowNode = {
              id,
              type,
              label,
              provider,
              position: newPos,
              status: 'active'
          };

          const newEdges = [...get().workflowEdges];
          if (parentId) {
              newEdges.push({ id: `e-${parentId}-${id}`, source: parentId, target: id });
          }

          set(state => ({ 
              workflowNodes: [...state.workflowNodes, newNode],
              workflowEdges: newEdges
          }));
      },

      updateWorkflowNodePosition: (id, x, y) => {
          set(state => ({
              workflowNodes: state.workflowNodes.map(n => n.id === id ? { ...n, position: { x, y } } : n)
          }));
      },

      updateNodeProvider: (nodeId, provider) => {
          set(state => ({
              workflowNodes: state.workflowNodes.map(n => n.id === nodeId ? { ...n, provider } : n)
          }));
      },

      deleteWorkflowNode: (id) => {
          set(state => ({
              workflowNodes: state.workflowNodes.filter(n => n.id !== id),
              workflowEdges: state.workflowEdges.filter(e => e.source !== id && e.target !== id)
          }));
      },

      askCortex: async (query) => {
          set({ isCortexThinking: true });
          const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: query, timestamp: Date.now() };
          set(state => ({ cortexMessages: [...state.cortexMessages, userMsg] }));

          setTimeout(() => {
              const aiMsg: ChatMessage = { 
                  id: (Date.now()+1).toString(), 
                  sender: 'ai', 
                  text: `I have found 12 similar patterns for "${query}". The most likely root cause is hydraulic pump cavitation (89% confidence).`, 
                  timestamp: Date.now() 
              };
              set(state => ({ 
                  cortexMessages: [...state.cortexMessages, aiMsg],
                  isCortexThinking: false
              }));
          }, 1500);
      }
    }),
    {
      name: 'os-storage',
      storage: createJSONStorage(() => sessionStorage),
    }
  )
);

import React, { useEffect, useState, useRef } from 'react';
import { useOS } from '../../store';
import { Mic, MicOff, Send, Loader2, Volume2, Square, AlertCircle, Radio, Wifi, Signal, Sparkles, ArrowRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

// --- AUDIO UTILS (PCM Handling) ---
const floatTo16BitPCM = (input: Float32Array) => {
    const output = new Int16Array(input.length);
    for (let i = 0; i < input.length; i++) {
        const s = Math.max(-1, Math.min(1, input[i]));
        output[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return output;
};

const base64ToUint8Array = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
};

// Safe access to API Key in browser environments
const getApiKey = () => {
  try {
    return process.env.API_KEY;
  } catch (e) {
    console.warn("process.env.API_KEY is not accessible.");
    return "";
  }
};

// --- SYSTEM PROMPT FOR BETTER EXTRACTION (GERMAN) ---
const PORTA_SYSTEM_PROMPT = `Du bist Porta, der intelligente KI-Dispatcher von AEDIL.
Sprache: Konsequent DEUTSCH.

Deine primäre Aufgabe ist die präzise Aufnahme von Störungsmeldungen für Industriegeräte.
Du musst sicherstellen, dass ALLE 6 folgenden Datenpunkte im Gespräch genannt und bestätigt werden:

1. KUNDE (Firmenname)
   - Frage gezielt: "Von welcher Firma rufen Sie an?"
   - Wiederhole zur Bestätigung: "Ich notiere als Kunde: [Firmenname]."

2. KONTAKT (Name des Anrufers)
   - Frage gezielt: "Wie ist Ihr Name?"
   - Wiederhole zur Bestätigung: "Hallo [Name]."

3. GERÄT (Modell & Seriennummer)
   - Frage gezielt: "Um welches Gerätemodell handelt es sich?"
   - Frage gezielt: "Haben Sie eine Seriennummer?"
   - Wiederhole: "Gerät [Modell] ist notiert."

4. FEHLERCODE (Falls vorhanden)
   - Frage: "Wird ein Fehlercode im Display angezeigt?"
   - Wiederhole: "Fehlercode [Code] erfasst."

5. SYMPTOM (Genaue Beschreibung)
   - Frage: "Beschreiben Sie das Problem genau. Was funktioniert nicht?"
   - Wiederhole kurz das Kernproblem.

6. PRIORITÄT (Dringlichkeit)
   - Frage: "Wie stark beeinträchtigt das den Betrieb? Steht die Produktion?"
   - Bestimme Priorität: "Stillstand" = Sehr Hoch, "Einschränkung" = Mittel/Hoch.

Verhaltensregeln:
- Sei professionell, effizient und freundlich.
- Führe das Gespräch aktiv. Wenn eine Info fehlt, frage sofort danach.
- Wenn der Nutzer undeutlich ist, frage nach.
- Erfinde keine Daten. Nutze nur das, was der Nutzer sagt.

Startsatz: "Hallo, hier ist Porta von AEDIL Service. Ich nehme Ihre Störung auf. Wie kann ich helfen?"`;

export const Porta: React.FC = () => {
  const { porta, addPortaMessage, finalizePortaSession, setPortaStatus } = useOS();
  const [isConnected, setIsConnected] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [volume, setVolume] = useState(0);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isRetrying, setIsRetrying] = useState(false);
  const [time, setTime] = useState(new Date());

  // Refs for Audio Context & Session
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const volumeAnimationFrame = useRef<number>(0);
  const reconnectTimeoutRef = useRef<any>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  // Transcription Accumulators
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Playback cursor
  const nextStartTimeRef = useRef<number>(0);

  // Time update for status bar
  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  // Safe scrolling to bottom preventing viewport jumps
  useEffect(() => {
    if (chatContainerRef.current) {
        chatContainerRef.current.scrollTo({
            top: chatContainerRef.current.scrollHeight,
            behavior: 'smooth'
        });
    }
  }, [porta.messages]);

  // CLEANUP ON UNMOUNT
  useEffect(() => {
    return () => {
      disconnectLiveSession(false);
    };
  }, []);

  // Flush pending text to the store so it's not lost
  const flushTranscripts = () => {
      let hasNewData = false;
      if (currentInputTranscription.current.trim()) {
          const userText = currentInputTranscription.current;
          addPortaMessage('user', userText);
          currentInputTranscription.current = '';
          hasNewData = true;
      }
      if (currentOutputTranscription.current.trim()) {
          addPortaMessage('ai', currentOutputTranscription.current);
          currentOutputTranscription.current = '';
          hasNewData = true;
      }
      return hasNewData;
  };

  const disconnectLiveSession = (shouldFinalize = false) => {
     if (reconnectTimeoutRef.current) {
         clearTimeout(reconnectTimeoutRef.current);
         reconnectTimeoutRef.current = null;
     }

     if (volumeAnimationFrame.current) {
         cancelAnimationFrame(volumeAnimationFrame.current);
     }

     flushTranscripts();

     if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
     }

     if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current.onaudioprocess = null;
        processorRef.current = null;
     }

     if (analyserRef.current) {
         analyserRef.current.disconnect();
         analyserRef.current = null;
     }

     if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.suspend().then(() => audioContextRef.current?.close()).catch(() => {});
        audioContextRef.current = null;
     }
     if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        inputAudioContextRef.current.suspend().then(() => inputAudioContextRef.current?.close()).catch(() => {});
        inputAudioContextRef.current = null;
     }

     setIsConnected(false);
     setPortaStatus('idle');
     setVolume(0);
     nextStartTimeRef.current = 0;
     sessionPromiseRef.current = null;

     if (shouldFinalize) {
         setTimeout(() => {
             // Finalize using the transcript only
             finalizePortaSession();
         }, 300);
     }
  };

  const handleEndCall = () => {
      // Changed to false to allow user to manually click "Ticket erstellen"
      // This prevents the app from closing immediately after the call.
      disconnectLiveSession(false);
  };

  const connectLiveSession = async () => {
    setErrorMsg(null);
    setIsRetrying(false);

    if (sessionPromiseRef.current) return;

    const apiKey = getApiKey();
    if (!apiKey) {
        setErrorMsg('No API Key found.');
        addPortaMessage('system', 'Error: No API Key found for Live connection.');
        return;
    }

    try {
        setPortaStatus('listening');
        addPortaMessage('system', 'Initializing voice uplink...');

        const stream = await navigator.mediaDevices.getUserMedia({ 
            audio: { 
                channelCount: 1, 
                echoCancellation: true,
                noiseSuppression: true,
                autoGainControl: true,
                sampleRate: 16000
            } 
        });
        mediaStreamRef.current = stream;

        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;

        const inputCtx = new AudioContextClass({ sampleRate: 16000 });
        inputAudioContextRef.current = inputCtx;

        const outputCtx = new AudioContextClass({ sampleRate: 24000 });
        audioContextRef.current = outputCtx;

        await inputCtx.resume();
        await outputCtx.resume();

        const source = inputCtx.createMediaStreamSource(stream);

        const analyser = inputCtx.createAnalyser();
        analyser.fftSize = 64; 
        analyser.smoothingTimeConstant = 0.5;
        analyserRef.current = analyser;

        const processor = inputCtx.createScriptProcessor(4096, 1, 1);
        processorRef.current = processor;

        source.connect(analyser);
        analyser.connect(processor);

        const muteNode = inputCtx.createGain();
        muteNode.gain.value = 0;
        processor.connect(muteNode);
        muteNode.connect(inputCtx.destination);

        const updateVolume = () => {
            if (!analyserRef.current) return;
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);

            let sum = 0;
            for(let i=0; i < dataArray.length; i++) sum += dataArray[i];
            const avg = sum / dataArray.length;

            setVolume(avg);
            volumeAnimationFrame.current = requestAnimationFrame(updateVolume);
        };
        updateVolume();

        const ai = new GoogleGenAI({ apiKey });

        // Configuration with enabled transcription
        const config = {
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
                },
                // IMPORTANT: Enable transcription to capture context for ticket generation
                inputAudioTranscription: {}, 
                outputAudioTranscription: {},
                systemInstruction: PORTA_SYSTEM_PROMPT
            }
        };

        const sessionPromise = ai.live.connect({
            model: config.model,
            config: config.config,
            callbacks: {
                onopen: () => {
                    console.log("[Porta] Connected");
                    setIsConnected(true);
                    addPortaMessage('system', 'Voice uplink established. Speak naturally.');

                    processor.onaudioprocess = (e) => {
                        if (inputCtx.state === 'suspended') {
                            inputCtx.resume();
                        }

                        const inputData = e.inputBuffer.getChannelData(0);
                        const pcm16 = floatTo16BitPCM(inputData);

                        const uint8 = new Uint8Array(pcm16.buffer);
                        let binary = '';
                        const len = uint8.byteLength;
                        for (let i = 0; i < len; i++) binary += String.fromCharCode(uint8[i]);
                        const b64 = btoa(binary);

                        sessionPromise.then(session => {
                            session.sendRealtimeInput({
                                media: {
                                    mimeType: 'audio/pcm;rate=16000',
                                    data: b64
                                }
                            });
                        }).catch(() => {});
                    };
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Transcription
                    if (msg.serverContent?.outputTranscription) {
                        currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
                    } 
                    if (msg.serverContent?.inputTranscription) {
                        const newText = msg.serverContent.inputTranscription.text;
                        currentInputTranscription.current += newText;
                    }

                    if (msg.serverContent?.turnComplete) {
                        flushTranscripts();
                    }

                    // Handle Audio Output
                    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (audioData) {
                        setPortaStatus('speaking');

                        const pcmData = base64ToUint8Array(audioData);
                        const int16Array = new Int16Array(pcmData.buffer);
                        const float32Array = new Float32Array(int16Array.length);
                        for (let i = 0; i < int16Array.length; i++) {
                            float32Array[i] = int16Array[i] / 32768.0;
                        }

                        const buffer = outputCtx.createBuffer(1, float32Array.length, 24000);
                        buffer.getChannelData(0).set(float32Array);

                        const source = outputCtx.createBufferSource();
                        source.buffer = buffer;
                        source.connect(outputCtx.destination);

                        const currentTime = outputCtx.currentTime;
                        if (nextStartTimeRef.current < currentTime) {
                            nextStartTimeRef.current = currentTime;
                        }
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += buffer.duration;

                        source.onended = () => {
                             if (outputCtx && outputCtx.currentTime >= nextStartTimeRef.current - 0.2) {
                                 setPortaStatus('listening');
                             }
                        };
                    }

                    if (msg.serverContent?.interrupted) {
                        console.log("[Porta] Interrupted");
                        nextStartTimeRef.current = 0;
                        setPortaStatus('listening');
                        flushTranscripts();
                    }
                },
                onclose: () => {
                    console.log("[Porta] Session Closed");
                    setIsConnected(false);
                    setPortaStatus('idle');
                    addPortaMessage('system', 'Connection closed.');
                    sessionPromiseRef.current = null;
                },
                onerror: (err) => {
                    console.error("[Porta] Error", err);
                    const msg = (err as any)?.message || "Connection Error";
                    // Only show network error if we haven't already
                    if (!errorMsg) {
                        setErrorMsg(msg);
                        addPortaMessage('system', `Connection disrupted: ${msg}`);
                    }
                    setIsConnected(false);
                    setPortaStatus('idle');
                    sessionPromiseRef.current = null;
                }
            }
        });

        sessionPromiseRef.current = sessionPromise;

        sessionPromise.catch(e => {
            console.error("[Porta] Connection Initialization Failed", e);
            setErrorMsg("Service Unavailable");
            addPortaMessage('system', 'Service unavailable. Retrying in 2s...');
            setIsConnected(false);
            setPortaStatus('idle');
            sessionPromiseRef.current = null;

            if (!isRetrying) {
                setIsRetrying(true);
                reconnectTimeoutRef.current = setTimeout(() => {
                    connectLiveSession();
                }, 2000);
            }
        });

    } catch (e) {
        console.error("Setup Failed", e);
        setErrorMsg('Setup Failed');
        addPortaMessage('system', 'Failed to initialize audio subsystem.');
        setIsConnected(false);
        setPortaStatus('idle');
        sessionPromiseRef.current = null;
    }
  };

  const handleSendText = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    addPortaMessage('user', inputValue);

    if (sessionPromiseRef.current && isConnected) {
         sessionPromiseRef.current.then(session => {
            session.sendRealtimeInput({
                 media: {
                     mimeType: 'text/plain',
                     data: btoa(inputValue)
                 }
            });
         });
    }
    setInputValue('');
  };

  return (
    <div className="relative w-[340px] h-[680px] bg-black rounded-[55px] shadow-[0_0_0_6px_#2a2a2a,0_20px_60px_rgba(0,0,0,0.6)] border-[4px] border-[#111] overflow-visible ring-1 ring-white/10 z-10 select-none font-sans mx-auto">
        {/* Dynamic Island / Notch */}
        <div className="absolute top-[11px] left-1/2 -translate-x-1/2 w-[100px] h-[28px] bg-black rounded-full z-[100] flex items-center justify-end pr-2 gap-1.5 pointer-events-none">
            <div className="w-1.5 h-1.5 rounded-full bg-blue-900/20 box-border border border-white/5"></div>
        </div>

        {/* Hardware Buttons */}
        <div className="absolute top-28 -left-[7px] w-[6px] h-8 bg-[#2a2a2a] rounded-l-md shadow-inner"></div> 
        <div className="absolute top-44 -left-[7px] w-[6px] h-14 bg-[#2a2a2a] rounded-l-md shadow-inner"></div> 
        <div className="absolute top-60 -left-[7px] w-[6px] h-14 bg-[#2a2a2a] rounded-l-md shadow-inner"></div> 
        <div className="absolute top-48 -right-[7px] w-[6px] h-20 bg-[#2a2a2a] rounded-r-md shadow-inner"></div> 

        {/* SCREEN CONTENT */}
        <div className="w-full h-full bg-[#0B0C15] flex flex-col relative overflow-hidden rounded-[48px]">

            {/* iOS Status Bar */}
            <div className="absolute top-0 left-0 w-full h-[44px] px-6 flex items-center justify-between text-white z-[60] pointer-events-none mix-blend-difference">
                <span className="text-[13px] font-semibold tracking-wide pl-1">
                    {time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false })}
                </span>
                <div className="flex items-center gap-1.5">
                    <Signal className="w-3.5 h-3.5 fill-current" />
                    <Wifi className="w-3.5 h-3.5" strokeWidth={2.5} />
                    <div className="w-5 h-2.5 rounded-[3px] border-[1.5px] border-current relative ml-0.5">
                        <div className="absolute inset-0.5 bg-current rounded-[1px]"></div>
                    </div>
                </div>
            </div>

            {/* Main Visualizer Area */}
            <div className="flex-1 flex flex-col items-center justify-center relative z-0 px-6 pt-10">

                {/* Header */}
                <div className="absolute top-12 flex flex-col items-center">
                    <div className="font-bold text-sm tracking-wide text-white flex items-center gap-2">
                            AEDIL Porta
                            {isConnected && (
                            <span className="flex items-center gap-1 text-[9px] text-emerald-400 bg-emerald-500/10 px-2 py-0.5 rounded-full border border-emerald-500/20">
                                <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                                LIVE
                            </span>
                            )}
                    </div>
                    <div className="text-[10px] text-slate-500 font-mono uppercase tracking-wider">Voice Intake Agent</div>
                </div>

                {/* Central Orb */}
                <div className="relative mb-8 mt-4">
                    {/* Glow Layer */}
                    <div 
                        className={`absolute inset-0 rounded-full blur-[60px] transition-all duration-300 ${
                            porta.status === 'listening' && isConnected ? 'bg-emerald-500/40' : 
                            porta.status === 'speaking' ? 'bg-indigo-500/50' : 'bg-white/5'
                        }`}
                        style={{ transform: `scale(${1.2 + (volume/40)})` }}
                    ></div>

                    {/* Waveform Ring */}
                    {isConnected && (
                        <motion.div 
                        className="absolute inset-[-10px] rounded-full border-2 border-white/10"
                        animate={{ 
                            scale: [1, 1.1 + (volume/200), 1],
                            opacity: [0.3, 0.6, 0.3]
                        }}
                        transition={{ duration: 1.5, repeat: Infinity, ease: "easeInOut" }}
                        />
                    )}

                    {/* Button Wrapper */}
                    <div className="relative flex items-center justify-center">
                        <button 
                            onClick={isConnected ? handleEndCall : connectLiveSession}
                            style={{ transform: `scale(${1 + (volume/250)})` }}
                            className={`w-32 h-32 rounded-full border-[3px] transition-all duration-300 flex items-center justify-center backdrop-blur-sm cursor-pointer z-10 ${
                            isConnected 
                                ? (porta.status === 'speaking' 
                                    ? 'border-indigo-400/60 bg-indigo-500/10 shadow-[0_0_60px_rgba(99,102,241,0.3)]' 
                                    : 'border-emerald-500/60 bg-emerald-500/10 shadow-[0_0_60px_rgba(16,185,129,0.3)]')
                                : 'border-white/10 bg-white/5 hover:border-amber-500/50 hover:bg-amber-500/5 hover:shadow-[0_0_40px_rgba(245,158,11,0.2)]'
                        }`}>
                            {porta.status === 'processing' ? (
                                <Loader2 className="w-12 h-12 text-white animate-spin" />
                            ) : isConnected ? (
                                porta.status === 'speaking' ? (
                                    <div className="flex flex-col items-center gap-2">
                                        <Volume2 className="w-10 h-10 text-indigo-400" />
                                        <span className="text-[9px] text-indigo-300 font-bold uppercase tracking-wider">Sprechen</span>
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center gap-2">
                                        <div className="flex gap-1 items-end h-8">
                                            <motion.div animate={{ height: [8, Math.max(12, volume/2), 8] }} transition={{ duration: 0.3, repeat: Infinity }} className="w-1.5 bg-emerald-500 rounded-full" />
                                            <motion.div animate={{ height: [12, Math.max(20, volume/1.5), 12] }} transition={{ duration: 0.4, repeat: Infinity }} className="w-1.5 bg-emerald-400 rounded-full" />
                                            <motion.div animate={{ height: [10, Math.max(16, volume/1.8), 10] }} transition={{ duration: 0.35, repeat: Infinity }} className="w-1.5 bg-emerald-500 rounded-full" />
                                        </div>
                                        <span className="text-[9px] text-emerald-300 font-bold uppercase tracking-wider">Zuhören</span>
                                    </div>
                                )
                            ) : (
                                <div className="flex flex-col items-center gap-3">
                                    <MicOff className="w-10 h-10 text-zinc-500" />
                                    <span className="text-[10px] uppercase tracking-widest font-bold text-zinc-500">Starten</span>
                                </div>
                            )}
                        </button>
                    </div>
                </div>

                {/* Status Text */}
                <div className="text-center space-y-2 w-full px-4 min-h-[50px]">
                    <h2 className="text-xl font-light tracking-tight transition-all text-white">
                        {isConnected 
                            ? (porta.status === 'speaking' ? "Porta antwortet..." : "Porta hört zu...")
                            : "Bereit für Aufnahme"}
                    </h2>
                    <p className="text-slate-500 text-xs flex items-center justify-center gap-2">
                        {errorMsg ? (
                            <span className="text-red-400 flex items-center gap-1"><AlertCircle className="w-3 h-3" /> {errorMsg}</span>
                        ) : (
                            isConnected 
                                ? <span className="flex items-center gap-1.5"><Radio className="w-3 h-3 text-emerald-400" /> Verbindung aktiv</span>
                                : "Tippen zum Starten"
                        )}
                    </p>
                </div>

                {/* MANUAL GENERATE BUTTON */}
                <AnimatePresence>
                {!isConnected && (
                    <motion.button
                        initial={{ opacity: 0, scale: 0.9, y: 10 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.9, y: 10 }}
                        onClick={() => finalizePortaSession()}
                        className="mt-6 bg-white/10 hover:bg-white/15 border border-white/10 backdrop-blur-md text-white px-6 py-2.5 rounded-full text-xs font-bold shadow-xl flex items-center gap-2 transition-all group active:scale-95"
                    >
                        <Sparkles className="w-3.5 h-3.5 text-indigo-400 group-hover:text-indigo-300" />
                        Ticket erstellen
                    </motion.button>
                )}
                </AnimatePresence>
            </div>

            {/* Chat History */}
            <div ref={chatContainerRef} className="h-40 px-4 pb-2 overflow-y-auto mask-fade-top space-y-2 z-10 relative no-scrollbar">
                <AnimatePresence>
                    {porta.messages.map((msg) => (
                        <motion.div 
                        key={msg.id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                        >
                            <div className={`max-w-[90%] px-3 py-2 rounded-2xl text-[11px] leading-relaxed border ${
                                msg.sender === 'user' 
                                ? 'bg-[#1C1C1E] text-white border-white/10 rounded-tr-sm' 
                                : msg.sender === 'system' 
                                    ? 'bg-transparent text-slate-500 border-transparent text-center w-full italic text-[10px]' 
                                    : 'bg-indigo-500/10 text-indigo-200 border-indigo-500/20 rounded-tl-sm'
                            }`}>
                                {msg.text}
                            </div>
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>

            {/* Controls */}
            <div className="h-20 bg-[#0A0A0A] border-t border-white/10 flex items-center px-4 gap-3 z-20 pb-4">
                <button 
                    onClick={isConnected ? handleEndCall : connectLiveSession}
                    className={`w-10 h-10 rounded-full flex items-center justify-center transition-all shrink-0 ${
                        isConnected 
                            ? 'bg-red-500/20 text-red-500 border border-red-500/50 hover:bg-red-500 hover:text-white' 
                            : 'bg-amber-500/20 hover:bg-amber-500/30 text-amber-500 border border-amber-500/50'
                    }`}
                >
                    {isConnected ? <Square className="w-3.5 h-3.5 fill-current" /> : <Mic className="w-4 h-4" />}
                </button>

                <form onSubmit={handleSendText} className="flex-1 relative">
                    <input 
                        type="text" 
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        placeholder={isConnected ? "Nachricht..." : "Verbinden..."}
                        disabled={!isConnected}
                        className="w-full h-10 bg-[#1C1C1E] border border-white/10 rounded-full px-4 pr-10 text-xs text-white focus:outline-none focus:border-amber-500/50 transition-colors disabled:opacity-50 placeholder:text-zinc-600"
                    />
                    <button 
                        type="submit"
                        disabled={!inputValue.trim() || !isConnected}
                        className="absolute right-1 top-1 bottom-1 w-8 bg-amber-600 rounded-full flex items-center justify-center disabled:opacity-30 disabled:bg-white/10 transition-colors hover:bg-amber-500 text-white"
                    >
                        <Send className="w-3.5 h-3.5" />
                    </button>
                </form>
            </div>

            {/* Home Indicator */}
            <div className="absolute bottom-1.5 left-1/2 -translate-x-1/2 w-32 h-1 bg-black/80 rounded-full z-[100] pointer-events-none backdrop-blur-md"></div>
        </div>
    </div>
  );
};

