        await new Promise(r => setTimeout(r, 600));
        pushStep('IoT', 'Analyze Motor Torque & Noise Profile', 'complete', { serial: '91145272' }, { result: 'Torque: Normal. Noise: None. Reset: Successful.' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('Reasoning', 'Applying Discriminator Logic', 'complete', {}, { result: 'No Noise + Reset Possible = Sensor Drift (Excludes Mechanical Blockage).' });

        await new Promise(r => setTimeout(r, 600));
        pushStep('Inventory', 'Checking Stock for Sensor 51470075', 'complete', { part: 'LAGER;SENSOR' }, { available: true, location: 'Van-Regal A2' });

        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Defekt am Lenk-Istwertgeber (Sensorlager)',
                confidence: 96,
                reasoning: 'Code 3160 deutet auf Soll-Ist-Abweichung hin. Kunde bestätigt explizit KEINE mechanischen Geräusche und Fehler ist resetbar. Dies schließt einen mechanischen Schaden (Drehkranz) aus. Diagnose: Elektrischer Drift im Sensorlager.',
                shortReasoning: 'Code 3160 + Kein Geräusch = Sensor.'
            },
            secondaryFaults: [
                { fault: 'Korrosion am Stecker X12', confidence: 5, reasoning: 'Mögliche sekundäre Ursache für Signalverlust.' }
            ],
            // Return specific parts from constants or create them on fly
            requiredParts: RECOMMENDED_PARTS.filter(p => p.id === '51470075' || p.id === '51144062'),
            reasoningChain: reasoningChain,
            isComplete: true
        };
    }

    const apiKey = getApiKey();
    if (!apiKey) {
        console.warn("No API Key - Running in Simulation Mode");
        return this.getSimulationResult(ticketId, ticket);
    }

    try {
        const ai = new GoogleGenAI({ apiKey });

        // Define the System Prompt with TECHNICAL REPORT LOGIC
        const systemInstruction = `You are Curio, an expert industrial reliability engineer.
        Follow the "Conversational Triage Strategy" report logic strictly.

        TRIAGE LOGIC (Decision Tree):

        CLUSTER 1: DRIVE & CHASSIS (Antrieb & Fahrwerk)
        - Triggers: "Hoppelt", "Vibration", "Noise", "Abgefahren". NO Error Codes.
        - Diagnosis: Worn Drive Wheel (Antriebsrad) or Load Wheels (Lasträder).
        - Action: Replace Wheels.

        CLUSTER 2: STEERING (Lenkung)
        - Scenario A: Error 3160.1 OR Silent Failure.
          -> Diagnosis: Steering Sensor Drift (Lenkistwertsensor).
          -> Action: Replace Sensor & Calibrate.
        - Scenario B: Error 3161.1 OR Grinding/Blocked.
          -> Diagnosis: Mechanical Blockage / Slewing Ring (Drehkranzlager).
          -> Action: Major Repair (Requires 2 Technicians).

        CLUSTER 3: HYDRAULICS
        - Scenario A: External Leak (Oil on floor). -> Hose/Seal.
        - Scenario B: Internal Drift (Sinking forks). -> Cylinder.

        Analyze the ticket:
        Equipment: ${ticket.equipment.model} (${ticket.equipment.serialNumber})
        Error: ${ticket.error.code}
        Report: ${ticket.error.customerReport}

        Return a JSON object with:
        {
           "primaryFault": { 
              "fault": string, 
              "confidence": number (integer 0-100), 
              "reasoning": string (Explain using the Cluster Logic above),
              "shortReasoning": string (max 15 words)
           },
           "secondaryFaults": [{ "fault": string, "confidence": number, "reasoning": string }]
        }
        `;

        const model = 'gemini-2.5-flash';
        const tools = [{ functionDeclarations: [queryManualsTool, checkInventoryTool, getHistoryTool, readTelemetryTool] }];

        // Start Chat Session
        const chat = ai.chats.create({
            model,
            config: { systemInstruction, tools }
        });

        // Initial Trigger
        let result = await chat.sendMessage({ message: "Diagnose this ticket using available tools." });

        // Loop for Function Calling (Max 5 turns)
        let loopCount = 0;
        while (result.functionCalls && result.functionCalls.length > 0 && loopCount < 5) {
            loopCount++;
            const functionResponses = await Promise.all(result.functionCalls.map(async (call) => {
                const name = call.name;
                const args = call.args as any;
                let response = {};

                // EXECUTE LOCAL "REAL" TOOLS against our "DB" (constants.ts)
                console.log(`[MCP] Executing Tool: ${name}`, args);

                if (name === 'queryManuals') {
                    // Logic from Report
                    const code = args.errorCode || ticket.error.code;
                    let manualText = "General Fault.";
                    if (code.includes('3160')) manualText = "3160.1: Sensor Drift. Steering angle implausible. Electrical.";
                    else if (code.includes('3161')) manualText = "3161.1: Control deviation. Motor draws current but no movement. Mechanical Blockage.";
                    else if (code.includes('E0015')) manualText = "E0015: Hydraulic Pump pressure failure.";

                    response = { result: manualText };
                    pushStep('Manuals', `Querying KB for ${code}`, 'complete', args, response);
                } 
                else if (name === 'readTelemetry') {
                    // Simulate based on Report Clusters
                    const report = ticket.error.customerReport.toLowerCase();
                    const desc = ticket.error.description.toLowerCase();

                    if (report.includes('grinding') || report.includes('knirschen') || report.includes('3161')) {
                         response = { steering_torque: "HIGH (Blocked)", motor_current: "Max Limit", sensor_angle: "Static" };
                    } else if (report.includes('vibrat') || report.includes('hoppelt')) {
                         response = { drive_motor_rpm: "Fluctuating", accelerometer_z: "High Frequency Shocks (Road Profile)" };
                    } else {
                         response = { system_status: "Normal" };
                    }
                    pushStep('IoT', `Reading sensors for ${args.serialNumber}`, 'complete', args, response);
                } 
                else if (name === 'getHistory') {
                    const similar = MOCK_TICKETS.filter(t => t.equipment.model === (args.equipmentModel || ticket.equipment.model)).length;
                    response = { 
                        matches_found: similar + 850, 
                        cluster_analysis: "Pareto: 45% Drive Wheels, 30% Steering, 20% Hydraulics" 
                    };
                    pushStep('History', `Analyzing fleet history for ${args.equipmentModel}`, 'complete', args, response);
                } 
                else if (name === 'checkInventory') {
                    const keyword = args.partKeywords || '';
                    const parts = RECOMMENDED_PARTS.filter(p => p.name.toLowerCase().includes(keyword.toLowerCase()));
                    response = { available: parts.map(p => ({ name: p.name, id: p.id, stock: p.quantity, inStock: p.inStock })) };
                    pushStep('Inventory', `Checking stock for "${keyword}"`, 'complete', args, response);
                }

                return {
                    id: call.id,
                    name: call.name,
                    response: { result: JSON.stringify(response) }
                };
            }));

            // Send tool outputs back to the model
            result = await chat.sendMessage({
                message: functionResponses.map(fr => ({ functionResponse: fr }))
            });
        }

        // Parse the final JSON response
        const text = result.text;
        const jsonBlock = text.match(/```json\n([\s\S]*?)\n```/)?.[1] || text.replace(/```json|```/g, '');
        let parsed;
        try {
            parsed = JSON.parse(jsonBlock);
            let conf = parsed.primaryFault?.confidence || 85;
            if (conf < 1) conf = Math.round(conf * 100);
            if (conf > 100) conf = 100;
            parsed.primaryFault.confidence = conf;

            if (!parsed.primaryFault.shortReasoning) {
               parsed.primaryFault.shortReasoning = parsed.primaryFault.reasoning.split('.')[0].substring(0, 50) + "...";
            }

            pushStep('Reasoning', 'Synthesizing final diagnosis', 'complete', {}, parsed);
        } catch (e) {
            console.warn("Failed to parse JSON from AI", text);
            parsed = {
                primaryFault: { 
                    fault: "Manual Investigation Required", 
                    confidence: 0, 
                    reasoning: "AI could not reach a deterministic conclusion.",
                    shortReasoning: "Manual Check."
                },
                secondaryFaults: []
            };
        }

        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: parsed.primaryFault,
            secondaryFaults: parsed.secondaryFaults || [],
            requiredParts: RECOMMENDED_PARTS, 
            reasoningChain: reasoningChain,
            isComplete: true
        };

    } catch (error) {
        console.error("AI Diagnosis Failed", error);
        return this.getSimulationResult(ticketId, ticket); // Fallback
    }
  },

  // Fallback Simulation for Demo without API Key
  getSimulationResult(ticketId: string, ticket: Ticket): Partial<Diagnosis> {
    const report = (ticket.error.customerReport || "").toLowerCase();

    // Scenario 1: Steering Blockage (The "Expensive" one from Report)
    // Trigger: 3161 or "Grinding/Knirschen"
    if (report.includes('grinding') || report.includes('knirschen') || report.includes('3161') || report.includes('block')) {
        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Mechanical Blockage - Slewing Ring (Drehkranzlager)',
                confidence: 96,
                reasoning: 'Cluster 2 Analysis: The reported "grinding noise" combined with blockage symptoms indicates mechanical failure of the Slewing Ring (Drehkranzlager). Error 3161.1 confirms control deviation due to physical resistance, ruling out sensor drift (3160).',
                shortReasoning: 'Noise + Blockage = Bearing Failure (Not Sensor)'
            },
            secondaryFaults: [
                { fault: 'Steering Motor Overload', confidence: 15, reasoning: 'Motor likely overheated due to blockage but may be functional.' }
            ],
            // Select specific parts from the constants list
            requiredParts: RECOMMENDED_PARTS.filter(p => p.name.includes('Drehkranz') || p.name.includes('Lenkmotor')),
            reasoningChain: [
                { id: '1', system: 'Manuals', action: 'Check Code 3161.1', status: 'complete', result: 'Mechanical Blockage', timestamp: Date.now() },
                { id: '2', system: 'IoT', action: 'Analyze Torque', status: 'complete', result: 'Blockage Detected', timestamp: Date.now() },
                { id: '3', system: 'History', action: 'Cluster Match', status: 'complete', result: 'Cluster 2: Steering', timestamp: Date.now() },
                { id: '4', system: 'Reasoning', action: 'Discriminator Check', status: 'complete', result: 'Noise confirmed', timestamp: Date.now() }
            ],
            isComplete: true
        };
    }

    // Default Fallback (Hydraulics or Generic) if no specific keywords
    return {
      ticketId,
      timestamp: Date.now(),
      primaryFault: {
        fault: 'Hydraulic Pump Motor Failure (Cluster 3)',
        confidence: 89,
        reasoning: 'Symptoms match Cluster 3 (Hydraulics). Lack of external oil leak suggests internal component failure or pump motor electrical fault.',
        shortReasoning: 'Cluster 3 match. No external leak.'
      },
      secondaryFaults: [],
      requiredParts: RECOMMENDED_PARTS.filter(p => p.name.includes('Hydraulik') || p.name.includes('Dicht')),
      reasoningChain: [
          { id: '1', system: 'Manuals', action: 'Analyze Symptom', status: 'complete', result: 'Hydraulic Fault', timestamp: Date.now() },
          { id: '2', system: 'IoT', action: 'Read Sensor Data', status: 'complete', result: 'Pressure Low', timestamp: Date.now() }
      ],
      isComplete: true
    };
  }
};

