    // Trigger: 3161 or "Grinding/Knirschen"
    if (report.includes('grinding') || report.includes('knirschen') || report.includes('3161') || report.includes('block')) {
        return {
            ticketId,
            timestamp: Date.now(),
            primaryFault: {
                fault: 'Mechanical Blockage - Slewing Ring (Drehkranzlager)',
                confidence: 96,
                reasoning: 'Cluster 2 Analysis: The reported "grinding noise" combined with blockage symptoms indicates mechanical failure of the Slewing Ring (Drehkranzlager). Error 3161.1 confirms control deviation due to physical resistance, ruling out sensor drift (3160).',
                shortReasoning: 'Noise + Blockage = Bearing Failure (Not Sensor)'
            },
            secondaryFaults: [
                { fault: 'Steering Motor Overload', confidence: 15, reasoning: 'Motor likely overheated due to blockage but may be functional.' }
            ],
            // Select specific parts from the constants list
            requiredParts: RECOMMENDED_PARTS.filter(p => p.name.includes('Drehkranz') || p.name.includes('Lenkmotor')),
            reasoningChain: [
                { id: '1', system: 'Manuals', action: 'Check Code 3161.1', status: 'complete', result: 'Mechanical Blockage', timestamp: Date.now() },
                { id: '2', system: 'IoT', action: 'Analyze Torque', status: 'complete', result: 'Blockage Detected', timestamp: Date.now() },
                { id: '3', system: 'History', action: 'Cluster Match', status: 'complete', result: 'Cluster 2: Steering', timestamp: Date.now() },
                { id: '4', system: 'Reasoning', action: 'Discriminator Check', status: 'complete', result: 'Noise confirmed', timestamp: Date.now() }
            ],
            isComplete: true
        };
    }

    // Default Fallback (Hydraulics or Generic) if no specific keywords
    return {
      ticketId,
      timestamp: Date.now(),
      primaryFault: {
        fault: 'Hydraulic Pump Motor Failure (Cluster 3)',
        confidence: 89,
        reasoning: 'Symptoms match Cluster 3 (Hydraulics). Lack of external oil leak suggests internal component failure or pump motor electrical fault.',
        shortReasoning: 'Cluster 3 match. No external leak.'
      },
      secondaryFaults: [],
      requiredParts: RECOMMENDED_PARTS.filter(p => p.name.includes('Hydraulik') || p.name.includes('Dicht')),
      reasoningChain: [
          { id: '1', system: 'Manuals', action: 'Analyze Symptom', status: 'complete', result: 'Hydraulic Fault', timestamp: Date.now() },
          { id: '2', system: 'IoT', action: 'Read Sensor Data', status: 'complete', result: 'Pressure Low', timestamp: Date.now() }
      ],
